package ru.memearena.vote.api; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.security.AuthenticatedUserPrincipal; import ru.memearena.vote.application.VoteService; @RestController @RequestMapping("/api/v1/votes") public class VoteController { private final VoteService service; private final RateLimiterService limits; public VoteController(VoteService service,RateLimiterService limits){this.service=service;this.limits=limits;} @PostMapping @Operation(summary="Submit vote") public ResponseEntity<SubmitVoteResponse> submit(@AuthenticationPrincipal AuthenticatedUserPrincipal p,@Valid @RequestBody SubmitVoteRequest r){limits.check("vote",p.sessionId().toString(),120,60); return ResponseEntity.status(HttpStatus.CREATED).body(service.submit(p.userId(),r.leftMemeId(),r.rightMemeId(),r.winnerMemeId()));} }
